from datetime import datetime
import threading

_context = threading.local()

def setup_audit_logging(session_factory):
    """Automatic audit logging for all tracked entities."""

    @event.listens_for(session_factory, "after_flush")
    def track_changes(session, flush_context):
        timestamp = datetime.utcnow()
        user_id = getattr(_context, 'current_user_id', None)

        # Handle inserts
        for obj in session.new:
            if not _is_auditable(obj):
                continue
            _write_audit_entry(
                obj, "INSERT",
                _snapshot_object(obj),
                timestamp=timestamp,
                user_id=user_id
            )

        # Handle updates - capture what changed
        for obj in session.dirty:
            if not _is_auditable(obj):
                continue
            state = inspect(obj)
            changes = {}

            for attr in state.attrs:
                if attr.key.startswith('_'):
                    continue
                hist = attr.history
                if not hist.has_changes():
                    continue

                old_val = hist.deleted[0] if hist.deleted else None
                new_val = hist.added[0] if hist.added else None

                # Skip unchanged
                if old_val == new_val:
                    continue

                change_entry = {"old": _serialize(old_val), "new": _serialize(new_val)}

                # For FK changes, include the related object for context
                if attr.key.endswith('_id'):
                    rel_name = attr.key[:-3]
                    if hasattr(obj, rel_name):
                        related = getattr(obj, rel_name)
                        if related is not None:
                            change_entry["related_repr"] = repr(related)
                            change_entry["related_type"] = type(related).__name__

                changes[attr.key] = change_entry

            if changes:
                _write_audit_entry(
                    obj, "UPDATE", changes,
                    timestamp=timestamp,
                    user_id=user_id
                )

        # Handle deletes
        for obj in session.deleted:
            if not _is_auditable(obj):
                continue
            _write_audit_entry(
                obj, "DELETE",
                _snapshot_object(obj),
                timestamp=timestamp,
                user_id=user_id
            )

def _is_auditable(obj):
    return getattr(obj.__class__, '__auditable__', True)

def _serialize(val):
    if hasattr(val, 'isoformat'):
        return val.isoformat()
    return val

def _snapshot_object(obj):
    state = inspect(obj)
    return {a.key: _serialize(getattr(obj, a.key))
